<script>
(function(){
  function track(eventName, props){
    if (window.gtag) gtag('event', eventName, props || {});
    if (window.plausible) window.plausible(eventName, {props: props || {}});
  }
  // Click tracking + conversion hints
  document.querySelectorAll('[data-cta]').forEach(el=>{
    el.addEventListener('click', ()=> {
      track('cta_click', {label: el.getAttribute('data-cta')});
      const conv = el.getAttribute('data-conv');
      if (conv) track(conv, {label: el.getAttribute('data-cta')});
    });
  });
  // Accordion tracking
  document.querySelectorAll('details[data-section]').forEach(dt=>{
    dt.addEventListener('toggle', ()=>{ if(dt.open) track('accordion_open', {section: dt.getAttribute('data-section')}); });
  });
  // Scroll-depth tracking (25/50/75/100)
  let marks = [25,50,75,100]; function onScroll(){
    const p = Math.round(100 * window.scrollY / (document.body.scrollHeight - window.innerHeight));
    marks = marks.filter(m => { if (p >= m) { track('scroll_depth', {percent:m}); return false; } return true; });
    if (!marks.length) window.removeEventListener('scroll', onScroll);
  }; window.addEventListener('scroll', onScroll);
  // Exit intent (desktop + mobile idle)
  const modal = document.getElementById('exitModal');
  const close = document.getElementById('exitClose');
  let shown=false;
  function showModal(){ if(!shown){ shown=true; modal.style.display='flex'; track('modal_show', {label:'exit'});}}
  document.addEventListener('mouseleave', e=>{ if(e.clientY<=0) showModal(); });
  let idle; function resetIdle(){ clearTimeout(idle); idle=setTimeout(showModal, 25000); }
  ['mousemove','keydown','touchstart','scroll'].forEach(ev=>document.addEventListener(ev, resetIdle)); resetIdle();
  if (close) close.addEventListener('click', (e)=>{ e.preventDefault(); modal.style.display='none'; track('modal_close', {label:'exit'}); });
})();
</script>


<script>
document.addEventListener("DOMContentLoaded", function(){
  const image = document.getElementById("heroImage");
  const video = document.getElementById("heroVideo");

  function startCycle(){
      image.style.opacity = "1";
      video.style.opacity = "0";
      video.pause();
      video.currentTime = 0;

      setTimeout(() => {
          image.style.opacity = "0";
          video.style.opacity = "1";
          video.play();
      }, 4000);
  }

  video.addEventListener("ended", startCycle);
  startCycle();
});
</script>


<script>
document.addEventListener("DOMContentLoaded", function(){

  function mediaLoop(imageId, videoId){
      const image = document.getElementById(imageId);
      const video = document.getElementById(videoId);
      if(!image || !video) return;

      function startCycle(){
          image.style.opacity = "1";
          video.style.opacity = "0";
          video.pause();
          video.currentTime = 0;

          setTimeout(() => {
              image.style.opacity = "0";
              video.style.opacity = "1";
              video.play();
          }, 4000);
      }

      video.addEventListener("ended", startCycle);
      startCycle();
  }

  mediaLoop("heroImage","heroVideo");
  mediaLoop("bathImage","bathVideo");

});
</script>

